import React, { useState } from 'react';
import { Compass, Map, Camera, Users, Zap } from 'lucide-react';

function App() {
  const [showAssistant, setShowAssistant] = useState(false);
  const [activeTab, setActiveTab] = useState('home');

  const stats = [
    { label: 'Km idag', value: '124', icon: <Compass className="w-5 h-5" /> },
    { label: 'Körtid', value: '2h 15m', icon: <Zap className="w-5 h-5" /> },
    { label: 'Stopp', value: '3', icon: <Map className="w-5 h-5" /> },
  ];

  const renderContent = () => {
    if (activeTab === 'home') {
      return (
        <div style={{ paddingBottom: '100px' }}>
          {/* Header med varmt välkomnande */}
          <header style={{ marginBottom: '30px' }}>
            <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: '0 0 5px 0' }}>Hej Buddy! 🚐</h1>
            <p style={{ color: '#636E72', margin: '0' }}>Solen går ner om 3 timmar. Letar vi nattplats?</p>
          </header>

          {/* Stats-sektionen (Nerd-stats) */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '10px', marginBottom: '30px' }}>
            {stats.map((stat, i) => (
              <div key={i} style={{ backgroundColor: '#FFF', padding: '15px', borderRadius: '15px', textAlign: 'center', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
                <div style={{ color: '#D35400', marginBottom: '5px', display: 'flex', justifyContent: 'center' }}>{stat.icon}</div>
                <div style={{ fontSize: '18px', fontWeight: 'bold' }}>{stat.value}</div>
                <div style={{ fontSize: '10px', color: '#95A5A6', textTransform: 'uppercase' }}>{stat.label}</div>
              </div>
            ))}
          </div>

          {/* Proaktiva Assistenten-snabbval */}
          <section>
            <h2 style={{ fontSize: '18px', marginBottom: '15px', fontWeight: 'bold' }}>Vad vill du göra nu?</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
              <button style={actionButtonStyle}>
                <Camera style={{ marginBottom: '8px' }} size={24} />
                <span>Fota & Logga</span>
              </button>
              <button onClick={() => setActiveTab('convoy')} style={actionButtonStyle}>
                <Users style={{ marginBottom: '8px' }} size={24} />
                <span>Min Konvoj</span>
              </button>
            </div>
          </section>

          {/* UTVECKLARKNAPP (För att testa panelen) */}
          <button 
            onClick={() => setShowAssistant(true)}
            style={{ position: 'fixed', bottom: '100px', right: '20px', backgroundColor: '#D35400', color: 'white', border: 'none', padding: '15px', borderRadius: '50px', fontWeight: 'bold', cursor: 'pointer', boxShadow: '0 4px 10px rgba(0,0,0,0.2)', zIndex: 10 }}>
            🛑 Stopp
          </button>
        </div>
      );
    } else if (activeTab === 'convoy') {
      return (
        <div style={{ textAlign: 'center', paddingTop: '50px' }}>
          <h1 style={{ fontSize: '24px', color: '#2D5A27' }}>Min Konvoj 🫂</h1>
          <p style={{ color: '#636E72' }}>Gemensam karta och röstningsfunktion kommer här.</p>
        </div>
      );
    } else if (activeTab === 'logbook') {
      return (
        <div style={{ textAlign: 'center', paddingTop: '50px' }}>
          <h1 style={{ fontSize: '24px', color: '#2D5A27' }}>Loggbok 📖</h1>
          <p style={{ color: '#636E72' }}>Dina minnen och TravelMap-export samlas här.</p>
        </div>
      );
    }
  };

  return (
    <div style={{ backgroundColor: '#F5F2ED', minHeight: '100vh', padding: '20px', fontFamily: 'sans-serif', color: '#2D3436' }}>

      {renderContent()}

      {/* --- PREMIUM-ANIMERAD ASSISTENT (Den list som kommer upp underifrån) --- */}
      <div style={{ ...overlayStyle, opacity: showAssistant ? 1 : 0, pointerEvents: showAssistant ? 'auto' : 'none' }}>
        <div style={{ ...bottomSheetStyle, transform: showAssistant ? 'translateY(0)' : 'translateY(100%)' }}>
          <h2 style={{ fontSize: '22px', color: '#2D5A27', marginBottom: '5px', marginTop: '0' }}>Härlig plats! 🌲</h2>
          <p style={{ color: '#636E72', marginBottom: '25px', lineHeight: '1.5' }}>
            Jag känner att vi har stannat. Det är 18°C och soligt just nu. Vill du spara platsen i loggboken?
          </p>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <button style={primaryBtnStyle}>☀️ Logga väder & plats</button>
            <button style={secondaryBtnStyle}>📸 Lägg till ett foto</button>
            <button style={secondaryBtnStyle}>🗺️ Dela med Konvojen</button>
          </div>
          <button onClick={() => setShowAssistant(false)} style={cancelBtnStyle}>Nej, vi ska bara sträcka på benen</button>
        </div>
      </div>

      {/* --- BOTTENMENY --- */}
      <nav style={{ position: 'fixed', bottom: '0', left: '0', right: '0', backgroundColor: '#FFF', padding: '15px', display: 'flex', justifyContent: 'space-around', borderTop: '1px solid #EEE', zIndex: 100 }}>
        <button onClick={() => setActiveTab('home')} style={{ background: 'none', border: 'none', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          <Compass color={activeTab === 'home' ? '#2D5A27' : '#BDC3C7'} size={24} />
          <span style={{ fontSize: '10px', marginTop: '4px', color: activeTab === 'home' ? '#2D5A27' : '#BDC3C7', fontWeight: activeTab === 'home' ? 'bold' : 'normal' }}>Hem</span>
        </button>
