        </button>
        <button onClick={() => setActiveTab('logbook')} style={{ background: 'none', border: 'none', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          <Map color={activeTab === 'logbook' ? '#2D5A27' : '#BDC3C7'} size={24} />
          <span style={{ fontSize: '10px', marginTop: '4px', color: activeTab === 'logbook' ? '#2D5A27' : '#BDC3C7', fontWeight: activeTab === 'logbook' ? 'bold' : 'normal' }}>Loggbok</span>
        </button>
      </nav>
    </div>
  );
}

